294	    methods (Access = protected)
295	        function dlAssignments = scheduleNewTransmissionsDL(obj, timeFrequencyResource, schedulingInfo)
296	            %scheduleNewTransmissionsDL Assign resources for new DL transmissions
297	            %   Overrides the parent method to inject DRL-based UE selection
298	            %   while keeping all other scheduler logic intact.
299	            %
300	            %   When EnableDRL=true and ResourceAllocationType=0 (RAT-0):
301	            %       Uses runSchedulingStrategyDRL_RAT0 for UE selection
302	            %   Otherwise:
303	            %       Calls parent scheduleNewTransmissionsDL method
304	
305	            % ===================================================================
306	            % DRL MOD START - Check DRL mode and RAT-0
307	            % ===================================================================
308	            schedulerConfig = obj.SchedulerConfig;
309	
310	            % ---------------------------------------------------------------
311	            % TRAINING MODE: layer-by-layer protocol (Python server)
312	            % ---------------------------------------------------------------
313	            
314	            % DRL MOD: Check if this slot is reserved for CSI-RS. If so, skip DRL scheduling.
315	            isCSIRSSlot = false;
316	            csirsConfig = obj.UEContext(1).ComponentCarrier(1).CSIRSConfiguration;
317	            if ~isempty(csirsConfig) && isnumeric(csirsConfig.CSIRSPeriod)
318	                slotNum = timeFrequencyResource.NSlot;
319	                frameNum = timeFrequencyResource.NFrame;
320	                numSlotsFrame = obj.CellConfig(1).NumSlotsFrame;
321	                if mod(numSlotsFrame*frameNum + slotNum - csirsConfig.CSIRSPeriod(2), csirsConfig.CSIRSPeriod(1)) == 0
322	                    isCSIRSSlot = true;
323	                end
