1093	        function mask = computeActionMask(obj, eligibleUEs, freqOccupancyBitmap, currentAllocation)
1094	            %computeActionMask Compute action mask for valid DRL actions
1095	            %   mask = computeActionMask(obj, eligibleUEs, freqOccupancyBitmap, currentAllocation)
1096	            %
1097	            %   Returns a logical mask [NumLayers x NumRBGs x (NumEligibleUEs+1)]
1098	            %   where mask(l,m,a) = true means action a is valid at layer l, RBG m
1099	            %
1100	            %   Masking rules:
1101	            %   1. RBGs occupied by retransmissions: only "no allocation" action valid
1102	            %   2. UE already allocated on RBG: that UE's action is invalid
1103	            %   3. MaxUsersPerRBG reached: all UE allocation actions invalid
1104	
1105	            numEligibleUEs = numel(eligibleUEs);
1106	            numRBGs = numel(freqOccupancyBitmap);
1107	            numActions = numEligibleUEs + 1;  % +1 for "no allocation"
1108	
1109	            % Initialize mask: all actions valid by default
1110	            mask = true(obj.NumLayers, numRBGs, numActions);
1111	
1112	            for rbg = 1:numRBGs
1113	                % Rule 1: RBG occupied by retransmission
1114	                if freqOccupancyBitmap(rbg)
1115	                    % Only "no allocation" action is valid
1116	                    mask(:, rbg, 1:numEligibleUEs) = false;
1117	                    continue;
1118	                end
1119	
1120	                % Check current allocation on this RBG
1121	                if ~isempty(currentAllocation)
1122	                    allocatedUEsThisRBG = find(currentAllocation(:, rbg) > 0);
1123	
1124	                    % Count allocated UEs
1125	                    numAllocated = numel(allocatedUEsThisRBG);
1126	
1127	                    % Rule 3: MaxUsersPerRBG check
1128	                    if numAllocated >= obj.MaxUsersPerRBG
1129	                        mask(:, rbg, 1:numEligibleUEs) = false;
1130	                        continue;
1131	                    end
1132	
1133	                    % Rule 2: Mask already allocated UEs
1134	                    for ue = allocatedUEsThisRBG'
1135	                        ueIdx = find(eligibleUEs == ue, 1);
1136	                        if ~isempty(ueIdx)
1137	                            mask(:, rbg, ueIdx) = false;
1138	                        end
1139	                    end
1140	                end
1141	            end
1142	        end
